     2|import { STORAGE_KEYS } from "@ai-whisperers/auth/storage-keys"
     3|
     4|let currentLang: Lang = "es"
     5|
     6|export function getLang(): Lang {
     7|  if (typeof window === "undefined") return "es"
     8|  try {
     9|    const saved = localStorage.getItem(STORAGE_KEYS.LANG) as Lang | null
    10|    if (saved && ["es", "en", "gn"].includes(saved)) return saved
    11|    const urlLang = new URLSearchParams(window.location.search).get("lang") as Lang | null
    12|    if (urlLang && ["es", "en", "gn"].includes(urlLang)) return urlLang
    13|  } catch {}
    14|  return "es"
    15|}
    16|
    17|export function setLang(lang: Lang) {
    18|  currentLang = lang
    19|  if (typeof window !== "undefined") localStorage.setItem(STORAGE_KEYS.LANG, lang)
    20|}
    21|
    22|export function t(key: string): string {
    23|  const lang = getLang()
    24|  if (lang === "es") return key
    25|  try {
    26|    const data = require(`@/content/${lang}.json`)
    27|    const parts = key.split(".")
    28|    let val: any = data
    29|    for (const p of parts) { if (val && typeof val === "object") val = val[p]; else return key }
    30|    if (typeof val === "string") return val
    31|  } catch {}
    32|  return key
    33|}
